	batchRunTests(t, []batchTestCase{
		{name: "Supported lua string function", tsCode: `
        declare global {
            interface String {
                upper(): string;
            }
        }
    
export const __result = "test".upper();`, accessor: `mod["__result"]`, want: `"TEST"`, refLua: `local ____exports = {}
____exports.__result = ("test"):upper()
return ____exports`},
	})

	t.Run("string.split inline", func(t *testing.T) {
		t.Parallel()
		expectExpression(t, `"a, b, c".split(",")`, `{"a", " b", " c"}`, WithOptions(map[string]any{"luaLibImport": "inline"}))
	})

	t.Run("string.split inline empty separator", func(t *testing.T) {
		t.Parallel()
		expectExpression(t, `"a, b, c".split("")`, `{"a", ",", " ", "b", ",", " ", "c"}`, WithOptions(map[string]any{"luaLibImport": "inline"}))
	})

	t.Run("prototype call on nullable string (\"\\\"foo\\\"\")", func(t *testing.T) {
		t.Parallel()
		expectFunction(t, `function toUpper(str?: string) {
            return str?.toUpperCase();
        }
        return toUpper("foo");`, `"FOO"`, WithOptions(map[string]any{"strictNullChecks": true}))
	})

	t.Run("prototype call on nullable string (\"undefined\")", func(t *testing.T) {
		t.Parallel()
		expectFunction(t, `function toUpper(str?: string) {
            return str?.toUpperCase();
        }
        return toUpper(undefined);`, `nil`, WithOptions(map[string]any{"strictNullChecks": true}))
	})

	t.Run("prototype call on nullable string type (\"string | undefined\")", func(t *testing.T) {
		t.Parallel()
		expectFunction(t, `function toUpper(str: string | undefined) {
            return str?.toUpperCase();
        }
        return toUpper("foo");`, `"FOO"`, WithOptions(map[string]any{"strictNullChecks": true}))
	})

	t.Run("prototype call on nullable string type (\"string | null\")", func(t *testing.T) {
		t.Parallel()
		expectFunction(t, `function toUpper(str: string | null) {
            return str?.toUpperCase();
        }
        return toUpper("foo");`, `"FOO"`, WithOptions(map[string]any{"strictNullChecks": true}))
	})

	t.Run("prototype call on nullable string type (\"null | string\")", func(t *testing.T) {
		t.Parallel()
		expectFunction(t, `function toUpper(str: null | string) {
            return str?.toUpperCase();
        }
        return toUpper("foo");`, `"FOO"`, WithOptions(map[string]any{"strictNullChecks": true}))
	})

	t.Run("prototype call on nullable string type (\"null | undefined | string\")", func(t *testing.T) {
		t.Parallel()
		expectFunction(t, `function toUpper(str: null | undefined | string) {
            return str?.toUpperCase();
        }
        return toUpper("foo");`, `"FOO"`, WithOptions(map[string]any{"strictNullChecks": true}))
	})
